# Problem: Implement Mediator (command dispatching) and Pub-Sub (event broadcasting)
# patterns for event-driven architecture, then wire them together in a user management system.
#
# Approach:
# - Mediator uses a dict mapping command types to handler callables (exact type match via type()).
# - EventBus uses a defaultdict(list) mapping event_type strings to lists of handlers.
# - build_user_system wires both together with an in-memory user store, publishing events
#   after successful data operations.
#
# Time complexity: O(1) for mediator dispatch, O(n) for pub-sub publish where n = subscriber count.
# Space complexity: O(h + s) where h = registered handlers, s = stored users.
#
# Key steps:
# 1. Implement Mediator with type-keyed handler registry
# 2. Implement EventBus with string-keyed subscriber lists
# 3. Wire together in build_user_system with CRUD handlers that publish events

import time
from typing import Any, Callable
from collections import defaultdict
from pydantic import BaseModel, Field


# Part 1: Mediator Pattern

class Command(BaseModel):
    """Base command class."""
    pass


class CommandResult(BaseModel):
    success: bool
    data: Any = None
    error: str | None = None


class Mediator:
    """Command/query dispatcher."""

    def __init__(self):
        self._handlers: dict[type, Callable] = {}  # exact type -> handler mapping

    def register(self, command_type: type, handler: Callable) -> None:
        self._handlers[command_type] = handler

    def send(self, command: Command) -> CommandResult:
        # Use type() for exact match — subclasses won't trigger parent handlers
        command_type = type(command)
        handler = self._handlers.get(command_type)
        if handler is None:
            return CommandResult(
                success=False,
                error=f"No handler for {command_type.__name__}"
            )
        return handler(command)


class CreateUserCommand(Command):
    name: str
    email: str


class DeleteUserCommand(Command):
    user_id: int


class GetUserQuery(Command):
    user_id: int


# Part 2: Pub-Sub Pattern

class Event(BaseModel):
    """Base event class."""
    event_type: str
    timestamp: float = Field(default_factory=time.time)


class EventBus:
    """Publish-subscribe event dispatcher."""

    def __init__(self):
        # defaultdict allows multiple handlers per event type without key checks
        self._subscribers: dict[str, list[Callable]] = defaultdict(list)

    def subscribe(self, event_type: str, handler: Callable) -> None:
        self._subscribers[event_type].append(handler)

    def unsubscribe(self, event_type: str, handler: Callable) -> bool:
        handlers = self._subscribers.get(event_type, [])
        try:
            handlers.remove(handler)
            return True
        except ValueError:
            return False  # handler was not subscribed

    def publish(self, event: Event) -> list:
        # Call every subscriber and collect return values
        results = []
        for handler in self._subscribers.get(event.event_type, []):
            results.append(handler(event))
        return results

    def get_subscribers(self, event_type: str) -> list[Callable]:
        return list(self._subscribers.get(event_type, []))  # return a copy


class UserCreatedEvent(Event):
    event_type: str = 'user_created'
    user_id: int
    name: str
    email: str


class UserDeletedEvent(Event):
    event_type: str = 'user_deleted'
    user_id: int


# Part 3: Wiring

def build_user_system() -> dict:
    """Build mediator + event bus + user store."""
    mediator = Mediator()
    event_bus = EventBus()
    users: dict[int, dict] = {}
    next_id = [1]  # mutable container so closures can modify it

    def handle_create_user(cmd: CreateUserCommand) -> CommandResult:
        user_id = next_id[0]
        user_data = {"id": user_id, "name": cmd.name, "email": cmd.email}
        users[user_id] = user_data
        next_id[0] += 1
        # Publish event AFTER successful data operation
        event_bus.publish(UserCreatedEvent(
            user_id=user_id, name=cmd.name, email=cmd.email
        ))
        return CommandResult(success=True, data=user_data)

    def handle_delete_user(cmd: DeleteUserCommand) -> CommandResult:
        if cmd.user_id not in users:
            return CommandResult(success=False, error=f"User {cmd.user_id} not found")
        del users[cmd.user_id]
        # Publish event AFTER successful deletion
        event_bus.publish(UserDeletedEvent(user_id=cmd.user_id))
        return CommandResult(success=True, data={"id": cmd.user_id})

    def handle_get_user(cmd: GetUserQuery) -> CommandResult:
        user = users.get(cmd.user_id)
        if user is None:
            return CommandResult(success=False, error=f"User {cmd.user_id} not found")
        return CommandResult(success=True, data=user)

    mediator.register(CreateUserCommand, handle_create_user)
    mediator.register(DeleteUserCommand, handle_delete_user)
    mediator.register(GetUserQuery, handle_get_user)

    return {"mediator": mediator, "event_bus": event_bus, "users": users}
